// // This module implements an 8-bit counter that decrements by 1 on each clock cycle unless the preset signal is high, in which case it loads the value from the preset_data input.
module counter_with_preset (
	input clk,
	input reset,
	input preset,
	input [7:0] preset_data,
	output reg [7:0] count);

	always @(posedge clk) begin
		if (reset)
			count <= 8'b00000000;
		else if (preset)
			count <= preset_data;
		else
			count <= count + 1;
	end

endmodule
